queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?departmentname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasDepartments ?child ; p:hasHospitals ?parent . } GROUP BY ?child }
  ?child p:departmentName ?departmentname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hospitals } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?departmentname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasDepartments ?child ; p:hasHospitals ?parent . } GROUP BY ?child }
  ?child p:departmentName ?departmentname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hospitals } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?departmentname WHERE {
  ?hospitals_departments a :Hospitals_Departments .
  ?departments a :Departments .
  ?hospitals_departments p:hasDepartments ?departments .
  ?hospitals a :Hospitals .
  ?hospitals_departments p:hasHospitals ?hospitals .
  ?hospitals p:name ?name .
  ?departments p:departmentName ?departmentname .
} }
}
